<!DOCTYPE html>
<html lang="{{ str_replace('_', '-', app()->getLocale()) }}">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Classes</title><link href="https://fonts.bunny.net/css?family=instrument-sans:400,500,600,700" rel="stylesheet" /><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css"><style>body{font-family:"Instrument Sans",sans-serif;background:linear-gradient(135deg,#020617,#0f172a 54%,#111827 100%);color:#e2e8f0;margin:0;padding:0}.container{max-width:1200px;margin:0 auto;padding:40px 20px}header{display:flex;justify-content:space-between;align-items:center;margin-bottom:40px;border-bottom:1px solid rgba(148,163,184,.1);padding-bottom:20px;gap:12px;flex-wrap:wrap}h1{color:#f8fafc;margin:0}.btn{background:linear-gradient(135deg,#22d3ee,#06b6d4);color:#082f49;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-weight:700;display:inline-flex;align-items:center;gap:8px}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:20px}.class-card{background:rgba(15,23,42,.78);border:1px solid rgba(148,163,184,.18);border-radius:16px;padding:20px}.class-name{color:#f8fafc;font-size:1.2rem;font-weight:700;margin:0 0 12px 0}.class-info{color:#94a3b8;font-size:.9rem;margin:8px 0}.trainer{color:#22d3ee;font-weight:600}.room{background:rgba(34,211,238,.1);padding:6px 12px;border-radius:6px;display:inline-block;font-size:.85rem}.stat{display:flex;justify-content:space-between;padding:8px 0;border-top:1px solid rgba(148,163,184,.1);margin-top:12px;color:#94a3b8;font-size:.85rem}</style></head>
<body><div class="container"><header><h1><i class="fa-solid fa-book"></i> All Classes</h1><div style="display:flex;gap:8px;flex-wrap:wrap">@auth<a class="btn" href="{{ route('dashboard') }}" style="background:rgba(34,211,238,.12);color:#22d3ee;border:1px solid rgba(34,211,238,.3)"><i class="fa-solid fa-arrow-left"></i> Back to Dashboard</a>@endauth<form method="POST" action="{{ route('logout') }}" style="display:inline">@csrf<button class="btn" type="submit"><i class="fa-solid fa-right-from-bracket"></i> Logout</button></form></div></header>@if($classes->count() > 0)<div class="grid">@foreach($classes as $cls)<div class="class-card"><h3 class="class-name">{{ $cls->name }}</h3><div class="class-info"><i class="fa-solid fa-chalkboard-user"></i> Trainer: <span class="trainer">{{ $cls->trainer->name }}</span></div><div class="class-info"><i class="fa-solid fa-circle-info"></i> Mode: <span class="room">{{ ucfirst($cls->delivery_mode ?? 'physical') }}</span></div><div class="class-info"><i class="fa-solid fa-location-dot"></i> Location: <span class="room">{{ $cls->room_number ?? 'Room not assigned' }}</span></div><div class="class-info"><i class="fa-regular fa-note-sticky"></i> {{ $cls->description ?: 'No description' }}</div><div class="stat"><span>Students:</span><strong>{{ $cls->students->count() }}</strong></div><div class="stat"><span>Assignments:</span><strong>{{ $cls->homeworks->count() }}</strong></div></div>@endforeach</div>@else<div style="background:rgba(34,211,238,.1);border:1px solid rgba(34,211,238,.3);padding:20px;border-radius:12px;text-align:center;color:#94a3b8"><i class="fa-regular fa-folder-open"></i> No classes available</div>@endif</div></body></html>
